.darma-loader-compass-spinner {
  position: relative;
  display: inline-block;
  width: 58px;
  height: 58px;
  border: 2px solid color-mix(in srgb, var(--loader-color, #6366f1) 22%, transparent);
  border-radius: 50%;
}
.darma-loader-compass-spinner::before {
  content: "";
  position: absolute;
  inset: 9px 25px;
  border-radius: 999px;
  background: var(--loader-color, #6366f1);
  transform-origin: 50% 20px;
  animation: darma-loader-compass-spinner-spin 1s cubic-bezier(.6,.2,.4,.8) infinite;
}
.darma-loader-compass-spinner::after {
  content: "";
  position: absolute;
  inset: 24px;
  border-radius: 50%;
  background: var(--loader-color, #6366f1);
}
@keyframes darma-loader-compass-spinner-spin { to { transform: rotate(360deg); } }

